<template>
  <div>
    <h2>SampleView 입니다. {{ sampleMsg }}</h2>
    <button @click="movemove">SampleView2로 데이터 전송하며 이동</button>
  </div>
</template>

<script>
export default {
  name: 'SampleView'
}
</script>

<script setup>
import { defineEmits } from 'vue'
import { useRouter } from 'vue-router'

const router = useRouter();
const emit = defineEmits(['routeParams']);

let sampleMsg = '안녕!';


function movemove() {
  emit('routeParams', {key1: 'apple', key2: 'grape'});
  router.push('/sample2');
}

</script>

